void test_CB_56_0000()
{
    if (skip_test_CB_56_0000)
    {
        TEST_SKIP("Skipping");
        return;
    }
    mmap.Reset();

    // Initial state

    WriteRegisterWord(RegisterType::PC, 0x206C);
    WriteRegisterWord(RegisterType::SP, 0x23F9);
    WriteRegisterByte(RegisterType::A, 0x0B);
    WriteRegisterByte(RegisterType::B, 0x92);
    WriteRegisterByte(RegisterType::C, 0x3A);
    WriteRegisterByte(RegisterType::D, 0x0E);
    WriteRegisterByte(RegisterType::E, 0xC5);
    WriteRegisterFlag(0xE0);
    WriteRegisterByte(RegisterType::H, 0xD4);
    WriteRegisterByte(RegisterType::L, 0x2A);
    mmap.EnableIME();
    WriteRegisterByte(RegisterType::IE, 0x01);
    WriteMemory(0xD42A, 0x97);
    WriteMemory(0x206D, 0x56);
    WriteMemory(0x206C, 0xCB);

    // Execute step
    {
        auto resultByte = mmap.ReadByte(mmap.ReadPC());
        TEST_ASSERT_(resultByte.IsSuccess(), "%s", resultByte.GetStatusDescription());
        auto ticks = ExecuteActiveDecoder(static_cast<const Byte&>(resultByte), mmap);
        TEST_ASSERT(ticks == GetInstructionTicks(static_cast<const Byte&>(resultByte), 0x00));

        // Execute additional step for prefix
        auto resultByte2 = mmap.ReadByte(mmap.ReadPC());
        TEST_ASSERT_(resultByte2.IsSuccess(), "%s", resultByte2.GetStatusDescription());
        auto ticks2 = ExecuteActiveDecoder(static_cast<const Byte&>(resultByte2), mmap);
        TEST_ASSERT(ticks2 == GetInstructionTicks(static_cast<const Byte&>(resultByte2), 0xCB));
        TEST_ASSERT(ticks + ticks2 == 12);
    }

    // Final state
            
    CheckRegisterByte(RegisterType::A, 0x0B);
    CheckRegisterByte(RegisterType::B, 0x92);
    CheckRegisterByte(RegisterType::C, 0x3A);
    CheckRegisterByte(RegisterType::D, 0x0E);
    CheckRegisterByte(RegisterType::E, 0xC5);
    CheckRegisterFlag(0x20);
    CheckRegisterByte(RegisterType::H, 0xD4);
    CheckRegisterByte(RegisterType::L, 0x2A);
    CheckRegisterWord(RegisterType::PC, 0x206E);
    CheckRegisterWord(RegisterType::SP, 0x23F9);
    TEST_ASSERT(mmap.IMEEnabled());
    CheckMemory(0x206C, 0xCB);
    CheckMemory(0x206D, 0x56);
    CheckMemory(0xD42A, 0x97);
}

